/**
 * @brief Test: Snapshot loading infrastructure
 *
 * Validates that PyTorch snapshots can be loaded correctly.
 */
TEST_F(Qwen2FP32Parity, SnapshotLoadingInfrastructure)
{
    // Try loading embedding snapshot
    auto embedding = loadPyTorchSnapshot("EMBEDDING");

    if (embedding.empty())
    {
        GTEST_SKIP() << "PyTorch snapshots not found. Run: python3 python/reference/generate_qwen2_pipeline_snapshots.py --output " << snapshot_dir_;
    }

    // Check embedding size
    // Expected: [batch=1, seq_len=9, d_model=896] = 8064 elements
    EXPECT_EQ(embedding.size(), 1 * 9 * 896) << "EMBEDDING snapshot size mismatch";

    LOG_INFO("[Parity] Successfully loaded EMBEDDING snapshot: " << embedding.size() << " elements");

    // Try loading layer 0 snapshots
    std::vector<std::string> test_stages = {
        "layer0_Q_PROJECTION",
        "layer0_ATTENTION_RESIDUAL",
        "layer0_FFN_RESIDUAL"};

    for (const auto &stage : test_stages)
    {
        auto data = loadPyTorchSnapshot(stage);
        EXPECT_FALSE(data.empty()) << "Failed to load " << stage;
        LOG_INFO("[Parity] Loaded " << stage << ": " << data.size() << " elements");
    }

    // Try loading final stages
    auto final_norm = loadPyTorchSnapshot("FINAL_NORM");
    auto lm_head = loadPyTorchSnapshot("LM_HEAD");

    EXPECT_FALSE(final_norm.empty()) << "Failed to load FINAL_NORM";
    EXPECT_FALSE(lm_head.empty()) << "Failed to load LM_HEAD";

    // Expected: LM_HEAD = [batch=1, seq_len=9, vocab_size=151936] = 1367424 elements
    EXPECT_EQ(lm_head.size(), 1 * 9 * 151936) << "LM_HEAD snapshot size mismatch";

    LOG_INFO("[Parity] Successfully loaded FINAL_NORM: " << final_norm.size() << " elements");
    LOG_INFO("[Parity] Successfully loaded LM_HEAD: " << lm_head.size() << " elements");
}
